// Versão que evita duplicidade entre Académico e Agendamento
const output = $json.output || "";
let intents = output.split(',').map(i => i.trim().toUpperCase()).filter(i => i !== "");

// Se for académico, removemos o agendamento geral para evitar mensagens duplas
if (intents.includes("ACADEMIC") && intents.includes("AGENDAMENTO")) {
  intents = intents.filter(i => i !== "AGENDAMENTO");
}

if (intents.length === 0) return [{ output: "CHAT" }];

return intents.map(intent => ({ output: intent }));

